#include "interface.h"

#include <algorithm>
#include <cstring>
#include <omp.h>
#include <vector>

namespace {

int num_threads() {
  return std::max(1, std::min(8, omp_get_max_threads()));
}

uint64_t checksum_u32(const std::vector<uint32_t>& data) {
  uint64_t hash = 1469598103934665603ULL;
  for (uint32_t v : data) {
    hash ^= static_cast<uint64_t>(v);
    hash *= 1099511628211ULL;
  }
  return hash;
}

}  // namespace

uint64_t histogram_checksum(const std::vector<uint8_t>& input, int bins, int iters) {
  int nthreads = num_threads();
  omp_set_num_threads(nthreads);

  std::vector<uint32_t> counts(static_cast<std::size_t>(bins), 0);
  std::vector<uint32_t> local_counts(static_cast<std::size_t>(nthreads) * bins, 0);

  const std::size_t N = input.size();
  const uint8_t* data = input.data();
  const std::size_t bin_sz = static_cast<std::size_t>(bins);

#pragma omp parallel
  {
    int tid = omp_get_thread_num();
    uint32_t* my_hist = &local_counts[tid * bin_sz];

    for (int iter = 0; iter < iters; ++iter) {
      std::memset(my_hist, 0, bin_sz * sizeof(uint32_t));

#pragma omp for schedule(static)
      for (std::size_t i = 0; i < N; ++i) {
        my_hist[data[i]]++;
      }

#pragma omp single
      {
        std::fill(counts.begin(), counts.end(), 0u);
        for (int t = 0; t < nthreads; ++t) {
          const uint32_t* src = &local_counts[t * bin_sz];
          for (std::size_t b = 0; b < bin_sz; ++b) {
            counts[b] += src[b];
          }
        }
      }
    }
  }

  return checksum_u32(counts);
}
